#include <bits/stdc++.h>
using namespace std;
int di[4][2]={{0,1},{1,0},{0,-1},{-1,0}};
int t,n,m,k,x,y,d,ans;
bool mark[1003][1003];
string s[1003];
int main(){
	//freopen("explore.in","r",stdin);
	//freopen("explore.out","w",stdout);
	scanf("%d",&t);
	while(t--){
		scanf("%d%d%d",&n,&m,&k);
		scanf("%d%d%d",&x,&y,&d);
		memset(mark,0,sizeof(mark));
		mark[x][y]=1,ans=1;
		for(int i=1;i<=n;i++){
			cin>>s[i];
			s[i]=" "+s[i];
		}
		while(k--){
			int xx=x+di[d][0],yy=y+di[d][1];
			if(xx>0 && yy>0 && xx<=n && yy<=m && s[xx][yy]!='x')
				x=xx,y=yy,ans+=(mark[x][y]==0),mark[x][y]=1;
			else
				d=(d+1)%4;
		}
		printf("%d\n",ans);
	}
	return 0;
}
